import { createRouter, createWebHistory } from 'vue-router'
import HomeView from '../views/HomeView.vue'
import { getAuth } from "firebase/auth";

const routes = [
  {
    path: '/home',
    name: 'home',
    component: HomeView,
    meta: {
      requiresAuth: true
    }
  },
  {
    path: '/hub',
    name: 'hub',
    component: () => import(/* webpackChunkName: "hub" */ '../views/HubView.vue'),
    meta: {
      requiresAuth: true
    }

  },
  {
    path: '/settings',
    name: 'settings',
    component: () => import(/* webpackChunkName: "hub" */ '../views/SettingsView.vue'),
    meta: {
      requiresAuth: true
    }
  },
  {
    path: '/hub/camera',
    name: 'camera',
    component: () => import(/* webpackChunkName: "camera" */ '../views/CameraHubView.vue')
  },
  {
    path: '/hub/products',
    component: () => import(/* webpackChunkName: "camera" */ '../components/TutorialsList.vue')
  },
  {
    path: '/hub/shops',
    name: 'shops',
    component: () => import(/* webpackChunkName: "shops" */ '../views/ShopsHubView.vue')
  },
  {
    path: '/hub/calculator',
    name: 'calculator',
    component: () => import(/* webpackChunkName: "CalcCal" */ '../views/CalcCalView.vue')
  },
  {
    path: '/hub/recipes',
    name: 'recipes',
    component: () => import(/* webpackChunkName: "CalcCal" */ '../views/RecipesView.vue')
  },
  {
    path: '/register',
    component: () => import(/* webpackChunkName: "Register" */ '../views/RegisterVeiw.vue')
  },
  {
    path: '/sign-in',
    component: () => import('../views/SignInView.vue')
  },
  {
    path: '/auth',
    component: () => import('../views/AuthorizationView.vue')
  }
]

const router = createRouter({
  history: createWebHistory(process.env.BASE_URL),
  routes
})

router.beforeEach((to, from, next) => {
  if (to.matched.some((record) => record.meta.requiresAuth)) {
    if (getAuth().currentUser) {
      next()
    } else {
      alert('Вам необходимо войти!')
      next('/auth')
    }
  } else {
    next()
  }
})

export default router
