<template>
  <div class="home">
    <div class="main">
      <div class="main-container">
        <div class="main-widgets">
          <div class="main-widgets__item">
            <a
              class="nuipogoda-iframe-informer"
              data-nuipogoda="informer1"
              href="https://minsk.nuipogoda.ru"
              style="
                width: 100%;
                max-width: 90%;
                height: 162px;
                display: flex;
                margin: 16px auto;
                box-shadow: 2px 4px 8px rgba(0, 0, 0, 0.15);
                border-radius: 16px;
                overflow: hidden;
              "
            ></a>
          </div>
          <div class="main-widgets__item">
            <h1>Режимы</h1>
            <div
              class="neumorphism-toggle"
              v-for="toggle in togglers"
              :key="toggle"
              :class="toggle.id"
            >
              <input type="checkbox" :id="toggle.id" v-model="toggle.checked" />
              <label
                :for="toggle.id"
                @click="togglePopup"
                v-if="toggle.id == 'door'"
              >
                <div class="switch">
                  <div class="dot"></div>
                </div>
                <span>{{ toggle.name }}</span>
              </label>
              <label :for="toggle.id" v-else>
                <div class="switch">
                  <div class="dot"></div>
                </div>
                <span>{{ toggle.name }}</span>
              </label>
            </div>
          </div>
          <div class="main-widgets__item">
            <h1>Температура</h1>
            <div class="control">
              <label for="temp">Температура холодильника</label>
              <span class="temp-value" v-html="tempValue + '°C'"></span>
              <input
                type="range"
                v-model="tempValue"
                min="-15"
                max="15"
                name="temp"
                id="temp"
              />
            </div>
            <div class="control">
              <label for="temp2">Температура морозильника</label>
              <span class="temp-value" v-html="tempValue2 + '°C'"></span>
              <input
                type="range"
                v-model="tempValue2"
                min="-35"
                max="0"
                name="temp"
                id="temp2"
              />
            </div>
          </div>
          <div class="main-widgets__item">
            <h1>Количество БЖУ</h1>

            <div class="summPFC">
              <ul>
                <li>
                  <span>Белки:</span>
                  {{ calcProteins() }}
                </li>
                <li>
                  <span>Жиры:</span>
                  {{ calcFats() }}
                </li>
                <li>
                  <span>Углеводы:</span>
                  {{ calcCarbohydrates() }}
                </li>
              </ul>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
  <PopupItemVue v-show="popupShow" />
</template>

