<script>
import PopupItemVue from "@/components/Popup/PopupItem.vue";
import TutorialDataService from "../services/TutorialDataService";

// @ is an alias to /src
// import HelloWorld from '@/components/HelloWorld.vue'
document.addEventListener("DOMContentLoaded", () => {
  setInterval(
    (function (a, f, g) {
      var e = a.createElement(f);
      e.async = 1;
      e.src = g;
      a = a.getElementsByTagName(f)[0];
      a.parentNode.insertBefore(e, a);
    })(document, "script", "//nuipogoda.ru/informer/nuipogoda.js"),
    2000
  );
});

export default {
  name: "HomeView",
  components: { PopupItemVue },
  data() {
    return {
      tutorials: [],
      togglers: [
        { id: "eco", name: "Энергосбережение", checked: true },
        { id: "freeze", name: "Размораживание", checked: false },
        { id: "silent", name: "Тихий режми", checked: true },
        { id: "door", name: "Закрытие двери", checked: false },
      ],
      currentTutorial: null,
      currentIndex: -1,
      popupShow: true,
      thread: "",
      temperatureFridge: [
        { id: 1, a_title: "-5" },
        { id: 2, a_title: "0" },
        { id: 3, a_title: "5" },
      ],
      tempValue: 0,
      tempValue2: -5,
    };
  },
  methods: {
    onDataChange(items) {
      let _tutorials = [];

      items.forEach((item) => {
        let key = item.key;
        let data = item.val();
        _tutorials.push({
          key: key,
          title: data.title,
          description: data.description,
          published: data.published,
          proteins: data.proteins,
          fats: data.fats,
          carbohydrates: data.carbohydrates,
        });
      });

      this.tutorials = _tutorials;
    },

    refreshList() {
      this.currentTutorial = null;
      this.currentIndex = -1;
    },

    setActiveTutorial(tutorial, index) {
      this.currentTutorial = tutorial;
      this.currentIndex = index;
    },

    removeAllTutorials() {
      TutorialDataService.deleteAll()
        .then(() => {
          this.refreshList();
        })
        .catch((e) => {
          console.log(e);
        });
    },

    calcProteins() {
      let pr = 0;
      for (let item of this.tutorials) {
        pr += Number(item.proteins);
      }
      return Number(pr);
    },
    calcFats() {
      let fats = 0;
      for (let item of this.tutorials) {
        fats += Number(item.fats);
      }
      return Number(fats);
    },
    calcCarbohydrates() {
      let carb = 0;
      for (let item of this.tutorials) {
        carb += Number(item.carbohydrates);
      }
      return Number(carb);
    },
    currentDate() {
      let date = new Date();
      return (date = date.toLocaleDateString());
    },
    togglePopup() {
      this.popupShow = !this.popupShow;
    },
  },
  mounted() {
    TutorialDataService.getAll().on("value", this.onDataChange);
  },
  beforeUnmount() {
    TutorialDataService.getAll().off("value", this.onDataChange);
  },
};
</script>
